// Minimal Chart stub for offline demo. For production include official Chart.js
class Chart{constructor(ctx, cfg){this.ctx=ctx;this.cfg=cfg;this.draw();} draw(){const c=this.ctx; if(!c) return; const w=c.canvas.width, h=c.canvas.height; c.fillStyle='rgba(255,255,255,0.03)'; c.fillRect(0,0,w,h); c.fillStyle='white'; c.fillText((this.cfg.data.datasets[0].data||[]).join(','),10,20);} } 
